import { MoreButton } from '@/components/more-button';
import { RAGFlowAvatar } from '@/components/ragflow-avatar';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { SearchInput } from '@/components/ui/input';
import { useSetModalState } from '@/hooks/common-hooks';
import {
  useFetchDialog,
  useGetChatSearchParams,
} from '@/hooks/use-chat-request';
import { cn } from '@/lib/utils';
import { PanelLeftClose, PanelRightClose, Plus } from 'lucide-react';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useHandleClickConversationCard } from '../hooks/use-click-card';
import { useSelectDerivedConversationList } from '../hooks/use-select-conversation-list';
import { ConversationDropdown } from './conversation-dropdown';

type SessionProps = Pick<
  ReturnType<typeof useHandleClickConversationCard>,
  'handleConversationCardClick'
> & {
  switchSettingVisible(): void;
  hasSingleChatBox: boolean;
  className?: string;
};
export function Sessions({
  hasSingleChatBox,
  handleConversationCardClick,
  switchSettingVisible,
  className,
}: SessionProps) {
  const { t } = useTranslation();
  const {
    list: conversationList,
    addTemporaryConversation,
    handleInputChange,
    searchString,
  } = useSelectDerivedConversationList();
  const { data } = useFetchDialog();
  const { visible, switchVisible } = useSetModalState(true);

  const handleCardClick = useCallback(
    (conversationId: string, isNew: boolean) => () => {
      handleConversationCardClick(conversationId, isNew);
    },
    [handleConversationCardClick],
  );

  const { conversationId } = useGetChatSearchParams();

  if (!visible) {
    return (
      <PanelRightClose
        className="cursor-pointer size-4 mt-8"
        onClick={switchVisible}
      />
    );
  }

  return (
    <section
      className={cn(
        'w-[296px] h-full min-h-0 overflow-hidden flex flex-col rounded-xl border border-[#e5e7eb] bg-white shadow-sm p-4',
        className,
      )}
    >
      <section className="flex items-center text-base justify-between gap-2">
        <div className="flex gap-3 items-center min-w-0">
          <RAGFlowAvatar
            avatar={data.icon}
            name={data.name}
            className="size-8"
          ></RAGFlowAvatar>
          <span className="flex-1 truncate">{data.name}</span>
        </div>
        <PanelLeftClose
          className="cursor-pointer size-4"
          onClick={switchVisible}
        />
      </section>
      <div className="flex justify-between items-center mb-3 pt-6">
        <div className="flex items-center gap-3">
          <span className="text-base font-bold">{t('chat.conversations')}</span>
          <span className="text-text-secondary text-xs">
            {conversationList.length}
          </span>
        </div>
        <Button
          variant={'ghost'}
          onClick={addTemporaryConversation}
          className="border border-[#d8e0ec] bg-white hover:bg-[#f8fafc]"
        >
          <Plus></Plus>
        </Button>
      </div>
      <div className="pb-4">
        <SearchInput
          onChange={handleInputChange}
          value={searchString}
          className="bg-[#f8fafc] border-[#d8e0ec]"
        ></SearchInput>
      </div>
      <div className="space-y-2 flex-1 overflow-auto pr-1">
        {conversationList.map((x) => (
          <Card
            key={x.id}
            onClick={handleCardClick(x.id, x.is_new)}
            className={cn(
              'cursor-pointer shadow-none border transition-colors bg-[#f8fafc] border-transparent hover:bg-[#f1f5f9]',
              {
                'bg-[#edf3ff] border-[#c7d7ec]': conversationId === x.id,
              },
            )}
          >
            <CardContent className="px-3 py-2.5 flex justify-between items-center group gap-1">
              <div className="truncate text-[14px]">{x.name}</div>
              <ConversationDropdown conversation={x}>
                <MoreButton></MoreButton>
              </ConversationDropdown>
            </CardContent>
          </Card>
        ))}
      </div>
      <div className="pt-3">
        <Button
          className="w-full border-[#d0d9e5] text-[#334155] hover:bg-[#f8fafc]"
          onClick={switchSettingVisible}
          disabled={!hasSingleChatBox}
          variant={'outline'}
        >
          {t('chat.chatSetting')}
        </Button>
      </div>
    </section>
  );
}
