'use client';

import {
  AgenticDeepReadFormFields,
  RetrievalModeFormField,
} from '@/components/agentic-deepread-item';
import { CrossLanguageFormField } from '@/components/cross-language-form-field';
import { RerankFormFields } from '@/components/rerank';
import { SimilaritySliderFormField } from '@/components/similarity-slider';
import { SwitchFormField } from '@/components/switch-fom-field';
import { TopNFormField } from '@/components/top-n-item';
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Textarea } from '@/components/ui/textarea';
import { UseKnowledgeGraphFormField } from '@/components/use-knowledge-graph-item';
import { RetrievalMode } from '@/constants/agentic-deepread';
import { useTranslate } from '@/hooks/common-hooks';
import { useEffect } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';
import { DynamicVariableForm } from './dynamic-variable';

export function ChatPromptEngine() {
  const { t } = useTranslate('chat');
  const form = useFormContext();
  const retrievalMode = useWatch({
    control: form.control,
    name: 'prompt_config.retrieval_mode',
  });
  const isAgenticDeepRead = retrievalMode === RetrievalMode.AgenticDeepRead;

  useEffect(() => {
    form.setValue(
      'prompt_config.use_kg',
      retrievalMode === RetrievalMode.Graph,
    );
    if (
      retrievalMode === RetrievalMode.AgenticDeepRead &&
      form.getValues('prompt_config.reasoning')
    ) {
      form.setValue('prompt_config.reasoning', false);
    }
  }, [form, retrievalMode]);

  return (
    <div className="space-y-8">
      <FormField
        control={form.control}
        name="prompt_config.system"
        render={({ field }) => (
          <FormItem>
            <FormLabel>{t('system')}</FormLabel>
            <FormControl>
              <Textarea {...field} rows={8} />
            </FormControl>
            <FormMessage />
          </FormItem>
        )}
      />
      {!isAgenticDeepRead && (
        <SimilaritySliderFormField isTooltipShown></SimilaritySliderFormField>
      )}
      {!isAgenticDeepRead && <TopNFormField></TopNFormField>}
      <SwitchFormField
        name={'prompt_config.refine_multiturn'}
        label={t('multiTurn')}
        tooltip={t('multiTurnTip')}
      ></SwitchFormField>
      <RetrievalModeFormField name="prompt_config.retrieval_mode" />
      {isAgenticDeepRead && (
        <AgenticDeepReadFormFields baseName="prompt_config.agentic_deepread" />
      )}
      {!isAgenticDeepRead && (
        <UseKnowledgeGraphFormField
          name="prompt_config.use_kg"
          disabled
        ></UseKnowledgeGraphFormField>
      )}
      {!isAgenticDeepRead && (
        <SwitchFormField
          name={'prompt_config.reasoning'}
          label={t('reasoning')}
          tooltip={t('reasoningTip')}
        ></SwitchFormField>
      )}
      {!isAgenticDeepRead && <RerankFormFields></RerankFormFields>}
      <CrossLanguageFormField></CrossLanguageFormField>
      <DynamicVariableForm></DynamicVariableForm>
    </div>
  );
}
