import EmbedDialog from '@/components/embed-dialog';
import { useShowEmbedModal } from '@/components/embed-dialog/use-show-embed-dialog';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { SharedFrom } from '@/constants/chat';
import { useSetModalState } from '@/hooks/common-hooks';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import {
  useFetchConversation,
  useGetChatSearchParams,
} from '@/hooks/use-chat-request';
import { cn } from '@/lib/utils';
import { isEmpty } from 'lodash';
import { ArrowUpRight, ChevronLeft, LogOut, Send } from 'lucide-react';
import { useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useParams } from 'umi';
import { useHandleClickConversationCard } from '../hooks/use-click-card';
import { ChatSettings } from './app-settings/chat-settings';
import { MultipleChatBox } from './chat-box/multiple-chat-box';
import { SingleChatBox } from './chat-box/single-chat-box';
import styles from './index.less';
import { Sessions } from './sessions';
import { useAddChatBox } from './use-add-box';
import { useSwitchDebugMode } from './use-switch-debug-mode';

export default function Chat() {
  const { id } = useParams();
  const { navigateToChatList } = useNavigatePage();
  const { t } = useTranslation();
  const { data: conversation } = useFetchConversation();

  const { handleConversationCardClick, controller } =
    useHandleClickConversationCard();
  const { visible: settingVisible, switchVisible: switchSettingVisible } =
    useSetModalState(true);
  const {
    removeChatBox,
    addChatBox,
    chatBoxIds,
    hasSingleChatBox,
    hasThreeChatBox,
  } = useAddChatBox();

  const { showEmbedModal, hideEmbedModal, embedVisible, beta } =
    useShowEmbedModal();

  const { conversationId, isNew } = useGetChatSearchParams();

  const { isDebugMode, switchDebugMode } = useSwitchDebugMode();

  useEffect(() => {
    const html = document.documentElement;
    const body = document.body;
    const previousHtmlOverflow = html.style.overflow;
    const previousBodyOverflow = body.style.overflow;
    const previousHtmlOverscroll = html.style.overscrollBehavior;
    const previousBodyOverscroll = body.style.overscrollBehavior;

    html.style.overflow = 'hidden';
    body.style.overflow = 'hidden';
    html.style.overscrollBehavior = 'none';
    body.style.overscrollBehavior = 'none';

    return () => {
      html.style.overflow = previousHtmlOverflow;
      body.style.overflow = previousBodyOverflow;
      html.style.overscrollBehavior = previousHtmlOverscroll;
      body.style.overscrollBehavior = previousBodyOverscroll;
    };
  }, []);

  if (isDebugMode) {
    return (
      <section className="h-full min-h-0 box-border bg-[#f6f8fb] flex flex-col overflow-hidden px-6 py-4">
        <div className="flex items-center justify-between pb-4 shrink-0">
          <span className="text-2xl">
            {t('chat.multipleModels')} ({chatBoxIds.length}/3)
          </span>
          <Button variant={'ghost'} onClick={switchDebugMode}>
            {t('chat.exit')} <LogOut />
          </Button>
        </div>
        <div className="flex-1 min-h-0">
          <MultipleChatBox
            chatBoxIds={chatBoxIds}
            controller={controller}
            removeChatBox={removeChatBox}
            addChatBox={addChatBox}
          ></MultipleChatBox>
        </div>
      </section>
    );
  }

  return (
    <section className={styles.page}>
      <div className={styles.backRow}>
        <Button
          variant="ghost"
          size="sm"
          onClick={navigateToChatList}
          className={styles.backButton}
        >
          <ChevronLeft className="size-4" />
          {t('common.back', { defaultValue: '返回' })}
        </Button>
      </div>
      <div className={styles.workspace}>
        <Sessions
          hasSingleChatBox={hasSingleChatBox}
          handleConversationCardClick={handleConversationCardClick}
          switchSettingVisible={switchSettingVisible}
          className={styles.sessionsPanel}
        ></Sessions>

        <Card className={styles.workspaceCard}>
          <CardContent className="flex p-0 h-full min-h-0 overflow-hidden">
            <Card
              className={cn(
                'flex flex-col flex-1 min-w-0',
                styles.innerChatCard,
              )}
            >
              <CardHeader
                className={cn(styles.chatHeader, {
                  'border-b': hasSingleChatBox,
                })}
              >
                <CardTitle className={styles.chatTitle}>
                  <div className="truncate">{conversation.name}</div>
                  <div className={styles.chatActions}>
                    <Button
                      variant={'outline'}
                      className={styles.inlineEmbedButton}
                      onClick={showEmbedModal}
                    >
                      <Send /> {t('common.embedIntoSite')}
                    </Button>
                    <Button
                      variant={'outline'}
                      className={styles.multiModelButton}
                      onClick={switchDebugMode}
                      disabled={
                        hasThreeChatBox ||
                        isEmpty(conversationId) ||
                        isNew === 'true'
                      }
                    >
                      <ArrowUpRight /> {t('chat.multipleModels')}
                    </Button>
                  </div>
                </CardTitle>
              </CardHeader>
              <CardContent className="flex-1 p-0 min-h-0">
                <SingleChatBox controller={controller}></SingleChatBox>
              </CardContent>
            </Card>
            {settingVisible && (
              <ChatSettings
                switchSettingVisible={switchSettingVisible}
              ></ChatSettings>
            )}
          </CardContent>
        </Card>
      </div>
      {embedVisible && (
        <EmbedDialog
          visible={embedVisible}
          hideModal={hideEmbedModal}
          token={id!}
          from={SharedFrom.Chat}
          beta={beta}
          isAgent={false}
        ></EmbedDialog>
      )}
    </section>
  );
}
